<?php
namespace App\Domain\GameHome;use App\Domain\Characters\Accounts\ActiveCharacterContext;use App\Models\GameHomeCard;use App\Models\User;use InvalidArgumentException;
final class GameHomeCardDestinationResolver{private $context;private $routes;private $characters=[];private $fallbacks=[];public function __construct(ActiveCharacterContext $context,GameHomeCardRouteCatalog $routes){$this->context=$context;$this->routes=$routes;}public function resolve(GameHomeCard $card,User $user){$type=$card->destination_type;if(!GameHomeCardDestinationType::supports($type))throw new InvalidArgumentException('Tipo de destino no válido.');if($type===GameHomeCardDestinationType::CHARACTER_SELECTOR)return route('characters.select');if($type===GameHomeCardDestinationType::ACTIVE_CHARACTER_OVERVIEW){$character=$this->activeCharacter($user);return$character?route('characters.overview',$character):$this->characterFallback($user);}if($type===GameHomeCardDestinationType::EXTERNAL_URL)return$this->external($card->destination_value);$definition=$this->routes->definition($card->destination_value);if(!$definition||!\Route::has($card->destination_value))throw new InvalidArgumentException('Ruta interna no aprobada.');if($definition['parameters']===GameHomeCardRouteCatalog::NONE)return route($card->destination_value);$character=$this->activeCharacter($user);return$character?route($card->destination_value,$character):$this->characterFallback($user);}public function validateConfiguration($type,$value){if(!GameHomeCardDestinationType::supports($type))throw new InvalidArgumentException('Tipo de destino no válido.');if(!GameHomeCardDestinationType::requiresValue($type)){if($value!==null&&$value!=='')throw new InvalidArgumentException('Este destino no admite un valor manual.');return null;}if($type===GameHomeCardDestinationType::ROUTE){if(!$this->routes->supports($value)||!\Route::has($value))throw new InvalidArgumentException('Ruta interna no aprobada.');return$value;}return$this->external($value);}private function activeCharacter(User $user){if(!array_key_exists($user->id,$this->characters))$this->characters[$user->id]=$this->context->current($user);return$this->characters[$user->id];}private function characterFallback(User $user){if(!isset($this->fallbacks[$user->id]))$this->fallbacks[$user->id]=$user->characters()->where('status','active')->exists()?route('characters.select'):route('characters.create');return$this->fallbacks[$user->id];}private function external($url){if(!is_string($url)||$url!==trim($url)||!filter_var($url,FILTER_VALIDATE_URL))throw new InvalidArgumentException('URL externa no válida.');$scheme=strtolower((string)parse_url($url,PHP_URL_SCHEME));if(!in_array($scheme,['http','https'],true))throw new InvalidArgumentException('Solo se permiten URLs HTTP o HTTPS.');return$url;}}
